# Monitor PTA authentication events from the agent server
# Event source: AzureADConnectAuthenticationAgent

# Key PTA event IDs:
# 1000 - Agent started
# 1001 - Agent registration succeeded
# 1002 - Agent connected to Service Bus
# 1005 - Authentication request received
# 1006 - Authentication succeeded
# 1007 - Authentication failed (wrong password)
# 1008 - Authentication failed (account locked)
# 1009 - Authentication failed (account disabled)
# 1010 - Authentication failed (password expired)

Get-EventLog -LogName Application -Source 'AzureADConnectAuthenticationAgent' `
    -EntryType Error, Warning -Newest 50 |
    Select-Object TimeGenerated, EventID, EntryType, Message | Format-Table -Wrap

# Count auth failures in the last hour to detect attack patterns
$since = (Get-Date).AddHours(-1)
Get-EventLog -LogName Application -Source 'AzureADConnectAuthenticationAgent' `
    -After $since | Where-Object { $_.EventID -in @(1007, 1008, 1009, 1010) } |
    Group-Object EventID | Select-Object Name, Count |
    ForEach-Object {
        $label = switch ($_.Name) {
            '1007' { 'Wrong password' }
            '1008' { 'Account locked' }
            '1009' { 'Account disabled' }
            '1010' { 'Password expired' }
            default { 'Other' }
        }
        "$label : $($_.Count) failures"
    }
